function _biz(menuObj){ return ({
  "@context":"https://schema.org","@type":"BarOrPub","name":"TapHouse Frankfurt",
  "description":"Craft beer bar with a modern Indian kitchen in Frankfurt am Main (Westend). 20 rotating taps, 120+ bottled beers, wine, spirits and alcohol-free options.",
  "servesCuisine":["Craft Beer","Indian"],"priceRange":"€€","telephone":"+49 69 60660989",
  "url":"https://www.taphousefrankfurt.com/","acceptsReservations":true,
  "openingHoursSpecification":[
    {"@type":"OpeningHoursSpecification","dayOfWeek":["Tuesday","Wednesday","Thursday","Friday"],"opens":"16:00","closes":"00:00"},
    {"@type":"OpeningHoursSpecification","dayOfWeek":"Saturday","opens":"12:00","closes":"00:00"},
    {"@type":"OpeningHoursSpecification","dayOfWeek":"Sunday","opens":"12:00","closes":"23:00"}
  ],
  "address":{"@type":"PostalAddress","streetAddress":"Mendelssohnstraße 51","postalCode":"60325","addressLocality":"Frankfurt am Main","addressRegion":"Hessen","addressCountry":"DE"},
  "hasMenu":menuObj }); }
function _menu(name, sections){ return {"@type":"Menu","name":name,"inLanguage":"en","hasMenuSection":sections.filter(x=>x.items.length).map(sec=>({"@type":"MenuSection","name":sec.name,
  "hasMenuItem":sec.items.map(it=>{const o={"@type":"MenuItem","name":it.name}; if(it.desc)o.description=it.desc; if(it.price)o.offers={"@type":"Offer","price":String(it.price),"priceCurrency":"EUR"}; return o;})}))}; }
function _tapSecs(tap){ return [{name:"Beers on Tap",items:tap.map(t=>({name:t.name,desc:[t.style,t.abv,t.ibu?t.ibu+" IBU":""].filter(Boolean).join(" · "),price:(t.prices.slice(-1)[0]||[])[1]}))}]; }
function _botSecs(bottle){ return Object.entries(bottle).map(([cat,items])=>({name:cat,items:items.map(it=>({name:it.name,desc:[it.style,it.abv,it.loc].filter(Boolean).join(" · "),price:it.price}))})); }
function _othSecs(o){ const S=[]; for(const [c,items] of Object.entries(o.spirits)) S.push({name:c,items:items.map(([n,a,p4])=>({name:n,desc:a,price:p4}))});
  S.push({name:"Alcohol-Free Cocktails",items:o.af_cocktails.map(([n,a,p])=>({name:n,desc:a+" non-alcoholic",price:p}))});
  S.push({name:"Wine",items:o.wine.map(([n,a,,g2,bo])=>({name:n,desc:a,price:bo||g2}))});
  S.push({name:"Softdrinks",items:o.soft.map(([n])=>({name:n}))});
  S.push({name:"Coffee",items:o.coffee.map(([n])=>({name:n}))}); return S; }

function build(tap, bottle, other, rmap, emblem, stamp){
  const T=tapPanel(tap,rmap), B=bottlePanel(bottle,rmap), O=otherPanel(other);
  const nTap=tap.length, nBot=Object.values(bottle).reduce((a,x)=>a+x.length,0);
  const S_tap=JSON.stringify(_biz(_menu('Tap Beers',_tapSecs(tap))));
  const S_bot=JSON.stringify(_biz(_menu('Bottled Beers',_botSecs(bottle))));
  const S_oth=JSON.stringify(_biz(_menu('Other Than Beer',_othSecs(other))));
  const S_all=JSON.stringify(_biz(_menu('Drinks',[..._tapSecs(tap),..._botSecs(bottle),..._othSecs(other)])));
  const TT={
    all:['Drinks Menu — TapHouse Frankfurt | Craft Beer Bar & Indian Kitchen, Frankfurt', `The full drinks menu at TapHouse Frankfurt: ${nTap} rotating craft beers on tap with live Untappd ratings, ${nBot}+ bottled beers, plus wine, spirits and alcohol-free options — a craft beer bar with a modern Indian kitchen in Frankfurt am Main.`, S_all],
    tap:[`Tap Beers — TapHouse Frankfurt | ${nTap} Craft Beers on Tap`, `Live tap list at TapHouse Frankfurt: ${nTap} rotating craft beers with Untappd ratings and tasting flights, paired with modern Indian cuisine. Mendelssohnstraße 51, Frankfurt am Main.`, S_tap],
    bottle:[`Bottled Beers — TapHouse Frankfurt | ${nBot}+ Craft Beers by Bottle & Can`, `${nBot} bottled and canned craft beers at TapHouse Frankfurt — alcohol-free, gluten-free, IPA, NEIPA, stout, sour, Trappist and more. Craft beer bar with Indian kitchen, Frankfurt am Main.`, S_bot],
    other:['Wine, Spirits & Drinks — TapHouse Frankfurt', 'Beyond beer at TapHouse Frankfurt: wine, gin, rum, whisky, alcohol-free ISH cocktails, softdrinks and coffee. Craft beer bar and Indian kitchen in Frankfurt am Main.', S_oth],
  };
  const intro=(txt)=>`<p class="intro">${txt}</p>`;
  const IN={
    tap:intro('The rotating <strong>craft beer tap list</strong> at <strong>TapHouse Frankfurt</strong> — a craft beer bar with a modern Indian kitchen in Frankfurt am Main. Ratings are live from Untappd.'),
    bottle:intro('The full <strong>bottled &amp; canned craft beer</strong> selection at <strong>TapHouse Frankfurt</strong>, Frankfurt am Main — searchable by style.'),
    other:intro('Wine, spirits, alcohol-free cocktails, softdrinks and coffee at <strong>TapHouse Frankfurt</strong> — craft beer bar &amp; Indian kitchen, Frankfurt am Main.'),
    all:intro('The complete <strong>drinks menu</strong> at <strong>TapHouse Frankfurt</strong> — craft beer on tap, bottled beers, wine, spirits and alcohol-free options in Frankfurt am Main.'),
  };
  const combined=page(TT.all[0],TT.all[1],TT.all[2], `<div class="wrap">${header('Drinks Menu')}${menunav(null)}${IN.all}<nav class="tabs"><button data-tab="tap" class="active">On Tap</button><button data-tab="bottle">Bottles</button><button data-tab="other">Other Drinks</button></nav><div id="tap" class="panel active">${T}</div><div id="bottle" class="panel">${B}</div><div id="other" class="panel">${O}</div>${footer(emblem,stamp)}</div>`, TABS_JS+FILTER_JS);
  const mk=(sub,panel,js,key)=>page(TT[key][0],TT[key][1],TT[key][2], `<div class="wrap standalone">${header(sub)}${menunav({tap:'tap-beers',bottle:'bottle-beers',other:'other-drinks'}[key])}${IN[key]}<div class="panel active">${panel}</div>${footer(emblem,stamp)}</div>`, js);
  return {
    'index.html': combined,
    'tap-beers/index.html': mk('Tap Beers', T, '', 'tap'),
    'bottle-beers/index.html': mk('Bottled Beers', B, FILTER_JS, 'bottle'),
    'other-drinks/index.html': mk('Other Than Beer', O, '', 'other')
  };
}

// Pull live Untappd ratings for ALL menu items (taps + bottles) via the UTFB API.
// Auth = HTTP Basic base64(email:token). Token comes from the UNTAPPD_API_TOKEN secret.
// Returns { norm(name): [rating, count] } or null if unavailable. Never throws.
async function fetchUntappdRatings(){
  const token = process.env.UNTAPPD_API_TOKEN;
  if(!token){ console.log('UNTAPPD_API_TOKEN not set — skipping API ratings'); return null; }
  const email = process.env.UNTAPPD_API_EMAIL || 'nanduri@infinitudegmbh.de';
  const loc   = process.env.UNTAPPD_LOCATION_ID || '33180';
  const H = { 'Authorization': 'Basic ' + Buffer.from(email + ':' + token).toString('base64'), 'Accept':'application/json' };
  const map = {};
  try{
    const mres = await fetch(`https://business.untappd.com/api/v1/locations/${loc}/menus`, { headers:H });
    if(!mres.ok){ console.log('UTFB menus HTTP', mres.status); return null; }
    const mjson = await mres.json();
    const menus = mjson.menus || mjson.data || (Array.isArray(mjson)?mjson:[]) || [];
    for(const m of menus){
      const id = m.id || m.menu_id; if(!id) continue;
      let r; try{ r = await fetch(`https://business.untappd.com/api/v1/menus/${id}?full=true`, { headers:H }); }catch(e){ continue; }
      if(!r || !r.ok) continue;
      const j = await r.json();
      const menu = j.menu || j.data || j;
      const sections = menu.sections || menu.menu_sections || [];
      for(const sec of sections){
        const items = sec.items || sec.section_items || [];
        for(const it of items){
          if(!globalThis.__utfbItemLogged){ globalThis.__utfbItemLogged=true; try{ console.log('UTFB sample item:', JSON.stringify(it).slice(0,700)); }catch(_e){} }
          const beer = it.beer || it;
          const bname = beer.name || it.name;                      // Untappd canonical beer name ("Pale Ale")
          const disp  = it.name || it.display_name || it.custom_name || bname; // venue display name (matches the print PDF)
          const brewery = beer.brewery || it.brewery || '';
          const rat  = (beer.rating!=null ? beer.rating : (it.rating!=null?it.rating:(it.custom_rating!=null?it.custom_rating:null)));
          const cnt  = beer.rating_count || beer.total_user_count || it.rating_count || it.total_count || 0;
          if(rat){ const r=[Number(rat), Number(cnt)||0];
            for(const key of [disp, bname, brewery&&(brewery+' '+bname), brewery&&(bname+' '+brewery)]){ if(key) map[norm(key)] = r; } }
        }
      }
    }
    console.log('UTFB API ratings fetched:', Object.keys(map).length, 'items');
    return Object.keys(map).length ? map : null;
  }catch(e){ console.log('UTFB API ratings error:', e.message); return null; }
}

// DEBUG: dump the full API menu structure to public/_api_raw.json so we can map fields precisely.
async function fetchUntappdMenusRaw(){
  const token = process.env.UNTAPPD_API_TOKEN; if(!token) return null;
  const email = process.env.UNTAPPD_API_EMAIL || 'nanduri@infinitudegmbh.de';
  const loc   = process.env.UNTAPPD_LOCATION_ID || '33180';
  const H = { 'Authorization':'Basic '+Buffer.from(email+':'+token).toString('base64'), 'Accept':'application/json' };
  try{
    const mres = await fetch(`https://business.untappd.com/api/v1/locations/${loc}/menus`, {headers:H});
    if(!mres.ok) return {error:'menus '+mres.status};
    const mjson = await mres.json();
    const menus = mjson.menus || mjson.data || (Array.isArray(mjson)?mjson:[]) || [];
    const SKIP = /unpublished|food|speisen/i;
    const out = { menuList: menus.map(m=>({id:m.id||m.menu_id, name:m.name})), menus:{} };
    for(const m of menus){ if(SKIP.test(m.name||'')) continue; const id=m.id||m.menu_id; if(!id) continue;
      const r=await fetch(`https://business.untappd.com/api/v1/menus/${id}?full=true`,{headers:H}); if(r.ok) out.menus[m.name]=await r.json(); }
    return out;
  }catch(e){ return {error:e.message}; }
}

// ---------- API -> menu data (single source of truth: Untappd for Business) ----------
// bnorm MUST match the normalisation used to build pdf/bottle_seed.json exactly.
function bnorm(s){ return (s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/ß/g,'ss').replace(/[’'`]/g,'').replace(/\([^)]*\)/g,'').replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim(); }
const CATS = ['Alcohol-Free','Gluten-Free','Lager','Pale Ale','Session IPA','IPA','NEIPA','Dark / Stout','Wheat','Fruity','Sour','Trappist / Belgian','Bock','Cider'];
// Fallback grouping for a NEW bottle Kiran adds that isn't in the frozen seed.
function styleToCat(style, abv){
  const s=(style||'').toLowerCase();
  if((abv>0 && abv<=0.5) || /non-alco|alcohol.?free|alkoholfrei/.test(s)) return 'Alcohol-Free';
  if(/gluten/.test(s)) return 'Gluten-Free';
  if(/cider|cidre/.test(s)) return 'Cider';
  if(/gose|sour|lambic|berliner|wild|gueuze|geuze/.test(s)) return 'Sour';
  if(/hazy|new england|neipa/.test(s)) return 'NEIPA';
  if(/session ipa/.test(s)) return 'Session IPA';
  if(/\bipa\b|india pale|ipl|india pale lager/.test(s)) return 'IPA';
  if(/pale ale|\bapa\b/.test(s)) return 'Pale Ale';
  if(/stout|porter|dark|schwarz|black|imperial/.test(s)) return 'Dark / Stout';
  if(/trappist|belg|dubbel|tripel|tripple|quad|saison|abbey|witbier/.test(s)) return 'Trappist / Belgian';
  if(/bock/.test(s)) return 'Bock';
  if(/wheat|weiss|weizen|hefe|wit/.test(s)) return 'Wheat';
  if(/fruit|mango|cherry|kriek|raspberr|pineapple/.test(s)) return 'Fruity';
  return 'Lager'; // Lager/Pils/Helles/Radler/Rauchbier/Red/Brown etc. — Kiran's default bucket
}
const _pct = v => (v && Number(v)>0) ? String(v).replace(/\.0+$/,'')+'%' : '';
const _ibu = v => v ? String(v).replace(/\.0+$/,'') : '';
const _combined = it => ((it.custom_brewery||it.brewery) ? (it.custom_brewery||it.brewery)+' ' : '') + (it.custom_name||it.name);
// Build tap + bottle (same shapes parseTap/parseBottle produce) from the raw API menus.
// Returns { tap, bottle, rmap } or null if the beer menus aren't present.
function apiTapBottle(raw, seed){
  const menus = raw && raw.menus; if(!menus) return null;
  const tapMenu = menus['Beers on Tap'], botMenu = menus['Bottled Beers'];
  if(!tapMenu || !botMenu) return null;
  const rmap = {};
  // ---- TAP (order = physical tap line; hidden items dropped) ----
  const tapItems = (tapMenu.menu.sections||[]).flatMap(s=>s.items||[]).filter(it=>!it.hidden);
  const tap = tapItems.map((it,idx)=>{
    const nm = _combined(it).replace(/\s+/g,' ').trim();
    const prices = (it.containers||[]).map(c=>{
      let sz=((c.container_size&&c.container_size.name)||'').replace(/Draft/ig,'').replace(/\(flight only\)/ig,'(flight)').replace(/\s+/g,' ').trim();
      return [sz, c.price!=null?Number(c.price).toFixed(2):''];
    });
    const rating = it.rating ? [Number(it.rating), it.rating_count||0] : [0,0];
    if(rating[0]) rmap[norm(nm)] = rating;
    return { num: idx+1, name: nm, loc: it.brewery_location||'', style: it.custom_style||it.style||'',
             abv: _pct(it.custom_abv||it.abv), ibu: _ibu(it.custom_ibu||it.ibu), prices,
             desc: (it.custom_description||it.description||'').replace(/\s+/g,' ').trim() };
  });
  // ---- BOTTLE (grouped into the frozen 14 categories; new bottles style-derived + logged) ----
  const seedKeys = Object.keys(seed||{}); const orderOf={}; seedKeys.forEach((k,i)=>orderOf[k]=i);
  const botItems = (botMenu.menu.sections||[]).flatMap(s=>s.items||[]).filter(it=>!it.hidden);
  const bucket={}; CATS.forEach(c=>bucket[c]=[]); const newbies=[];
  for(const it of botItems){
    const nm=_combined(it).replace(/\s+/g,' ').trim(); const key=bnorm(nm);
    let ci; if(seed && key in seed) ci=seed[key];
    else { ci=CATS.indexOf(styleToCat(it.style||'', Number(it.abv)||0)); newbies.push(nm+' → '+(CATS[ci]||'Lager')); }
    if(ci<0||ci==null) ci=CATS.indexOf('Lager');
    const c0=(it.containers||[])[0]||{};
    const size=((c0.container_size&&c0.container_size.name)||'').replace(/Bottle|Can|Draft/ig,'').replace(/\s+/g,'').trim();
    const rating = it.rating ? [Number(it.rating), it.rating_count||0] : [0,0];
    if(rating[0]) rmap[norm(nm)] = rating;
    bucket[CATS[ci]].push({ _o:(key in orderOf)?orderOf[key]:9999, name:nm, loc:it.brewery_location||'',
      style: it.custom_style||it.style||'', abv:_pct(it.custom_abv||it.abv), size, price: c0.price!=null?Number(c0.price).toFixed(2):'' });
  }
  const bottle={};
  for(const c of CATS){ const arr=bucket[c].sort((a,b)=>a._o-b._o).map(({_o,...r})=>r); if(arr.length) bottle[c]=arr; }
  if(newbies.length) console.log('New/unseeded bottles (auto-grouped by style):', newbies.join(' | '));
  return { tap, bottle, rmap };
}

// ---- Non-beer drinks: overlay LIVE Untappd prices + ABV onto the curated structure ----
// The API carries spirits/wine/AF in the same section + order as the curated list, so we
// overlay by position (no name matching). Names, labels, wine sub-groups and soft/coffee
// serving sizes (which the API does not store) stay curated. Safe: if a section's count
// changes in Untappd, that section keeps its curated values and logs a notice.
const _fmtAbv = v => v ? (String(v).replace(/\.0$/,'')+'%') : '';
function _apiDrinkList(raw, menuName, sectionName){
  const m = raw && raw.menus && raw.menus[menuName]; if(!m) return null;
  const secs = sectionName ? (m.menu.sections||[]).filter(s=>s.name===sectionName) : (m.menu.sections||[]);
  return secs.flatMap(s=>s.items||[]).filter(it=>!it.hidden).map(it=>({
    name:(it.custom_name||it.name), abv:it.abv||'',
    prices:(it.containers||[]).map(c=>c.price!=null?Number(c.price).toFixed(2):'') }));
}
function _apiSpiritSections(raw){
  const m = raw && raw.menus && raw.menus['Spirits']; if(!m) return null;
  const o={}; for(const s of (m.menu.sections||[])){
    o[s.name]=(s.items||[]).filter(it=>!it.hidden).map(it=>({name:(it.custom_name||it.name), abv:it.abv||'',
      prices:(it.containers||[]).map(c=>c.price!=null?Number(c.price).toFixed(2):'')})); }
  return o;
}
function apiOther(raw, cur){
  const out = JSON.parse(JSON.stringify(cur)); // deep clone; mixers/soft/coffee kept as-is
  // SPIRITS — align curated sections to API sections by index (Gin, Rum, Bourbon, Single Malt, Shots)
  const sp = _apiSpiritSections(raw);
  if(sp){ const curKeys=Object.keys(out.spirits), apiKeys=Object.keys(sp);
    curKeys.forEach((ck,si)=>{ const aItems = sp[apiKeys[si]] || sp[ck]; if(!aItems) return; const cItems=out.spirits[ck];
      if(aItems.length>=cItems.length){
        out.spirits[ck]=aItems.map((a,i)=>{ const c=cItems[i];
          return [ c?c[0]:a.name, (c&&c[1])?c[1]:_fmtAbv(a.abv), a.prices[0]||(c?c[2]:''), a.prices[1]||(c?c[3]:'') ]; });
      } else console.log('Spirits/'+ck+' shrank in Untappd — keeping curated for that section'); });
  }
  // AF COCKTAILS — overlay price by position; append any new API items
  const af=_apiDrinkList(raw,'Alcohol Free Spirits');
  if(af && af.length>=out.af_cocktails.length){
    out.af_cocktails=out.af_cocktails.map((c,i)=> af[i]?[c[0],c[1],af[i].prices[0]||c[2]]:c);
    for(let i=out.af_cocktails.length;i<af.length;i++) out.af_cocktails.push([af[i].name,_fmtAbv(af[i].abv),af[i].prices[0]||'']);
  }
  // WINE group — API "Wine" section = wine(n) + wine_special(n) + wine_na(n), in that order
  const wine=_apiDrinkList(raw,'Wine, Softdrinks and Coffee','Wine');
  if(wine){ const nW=out.wine.length, nS=out.wine_special.length, nN=out.wine_na.length;
    if(wine.length===nW+nS+nN){
      out.wine=out.wine.map((c,i)=>{ const a=wine[i]; return [c[0], _fmtAbv(a.abv)||c[1], a.prices[0]||c[2], a.prices[1]||c[3], a.prices[2]||c[4]]; });
      out.wine_special=out.wine_special.map((c,j)=>{ const a=wine[nW+j]; return [c[0], c[1], c[2], a.prices[0]||c[3], c[4]]; });
      out.wine_na=out.wine_na.map((c,k)=>{ const a=wine[nW+nS+k]; return [c[0], _fmtAbv(a.abv)||c[1], a.prices[0]||c[2], a.prices[1]||c[3], a.prices[2]||c[4]]; });
    } else console.log('Wine list size changed in Untappd ('+wine.length+' vs '+(nW+nS+nN)+') — keeping curated wine');
  }
  return out;
}

